def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif 0.9 < ratio < 1:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.log1p(1/(ratio*10)) + 0.2
        elif 0.4 < ratio <= 0.7:
            for k in range(1, 8):
                term = ((-1)**(k+1)) * (ratio ** (k+2)) / (k**2 + 1)
                score += term
            score = abs(score) + 0.08
        else:
            s = 0
            for k in range(1, 11):
                inner_sum = 0
                for m in range(1, k+1):
                    inner_sum += (ratio ** m) / (m*2)
                s += ((-1)**k) * inner_sum / (k + 0.5)
            score = abs(s) + 0.02
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            local_influence = 0.0
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    local_influence += diff_ratio * weight * 0.05
            neighbors_influence += local_influence
        capacity_factor = np.sqrt(capacity) * (1 + 0.1 * np.sin(capacity))
        if capacity_factor <= 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        left_neighbors = bins[max(0, i-3):i]
        right_neighbors = bins[i+1:min(n, i+4)]
        left_avg = np.mean(left_neighbors) if left_neighbors.size > 0 else 0
        right_avg = np.mean(right_neighbors) if right_neighbors.size > 0 else 0
        if left_avg > capacity and right_avg > capacity:
            priority *= 0.85
        elif left_avg < capacity and right_avg < capacity:
            priority *= 1.15
        else:
            priority *= 1.0 + 0.05 * (right_avg - left_avg) / (capacity + 1e-5)
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10
        elif priorities[i] > max_finite:
            priorities[i] = max_finite
    return priorities
